     1→/*
     2→ * floor() test harness — prints (input_hex, output_hex) pairs.
     3→ *
     4→ * Build two versions:
     5→ *   1. Linked with optimized Andes assembly floor  (test_floor_opt.elf)
     6→ *   2. Linked with toolchain's default floor        (test_floor_ref.elf)
     7→ * Run both, diff the output to find discrepancies.
     8→ */
     9→
    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <float.h>
    14→
    15→#ifdef EN_PERF
    16→#define PF_COUNTER
    17→#include "nds_pfcounter.h"
    18→#endif
    19→
    20→static inline uint64_t d2u(double d)
    21→{
    22→    union { double d; uint64_t u; } x;
    23→    x.d = d;
    24→    return x.u;
    25→}
    26→
    27→static inline double u2d(uint64_t u)
    28→{
    29→    union { double d; uint64_t u; } x;
    30→    x.u = u;
    31→    return x.d;
    32→}
    33→
    34→static volatile double g_acc;
    35→
    36→static void emit(double x)
    37→{
    38→#ifdef EN_PERF
    39→    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    40→    g_acc += floor(vx);
    41→#else
    42→    double r = floor(x);
    43→    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
    44→#endif
    45→}
    46→
    47→static void emit_u(uint64_t bits)
    48→{
    49→    emit(u2d(bits));
    50→}
    51→
    52→/* ------------------------------------------------------------------ */
    53→/* Test points                                                         */
    54→/* ------------------------------------------------------------------ */
    55→
    56→static void test_representative_100(void)
    57→{
    58→    /* --- Section 1: Special IEEE 754 values (7) --- */
    59→    emit(0.0);
    60→    emit(-0.0);
    61→    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    62→    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    63→    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    64→    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    65→    emit_u(0xfff0000000000000ULL);  /* -Inf */
    66→
    67→    /* --- Section 2: Subnormal (denormal) values (6) --- */
    68→    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074, rounds to 0.0 */
    69→    emit_u(0x8000000000000001ULL);  /* min negative subnormal, rounds to -1.0 */
    70→    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    71→    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    72→    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    73→    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */
    74→
    75→    /* --- Section 3: Normal boundary values (4) --- */
    76→    emit(DBL_MIN);                  /* 2^-1022, smallest normal positive, rounds to 0.0 */
    77→    emit(-DBL_MIN);                 /* smallest normal negative, rounds to -1.0 */
    78→    emit_u(0x7fefffffffffffffULL);  /* DBL_MAX: large exact integer */
    79→    emit_u(0xffefffffffffffffULL);  /* -DBL_MAX */
    80→
    81→    /* --- Section 4: ULP neighbors of 1.0 and 2.0 (8) --- */
    82→    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0: 0.9999999999999998 */
    83→    emit(1.0);
    84→    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0: 1.0000000000000002 */
    85→    emit_u(0x3feffff000000000ULL);  /* a few ULPs below 1.0 */
    86→    emit(-1.0);
    87→    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    88→    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */
    89→    emit_u(0x4000000000000000ULL);  /* exactly 2.0 */
    90→
    91→    /* --- Section 5: Half-integer values n+0.5 for n=0..5 and negatives (12) --- */
    92→    emit(0.5);
    93→    emit(1.5);
    94→    emit(2.5);
    95→    emit(3.5);
    96→    emit(4.5);
    97→    emit(5.5);
    98→    emit(-0.5);
    99→    emit(-1.5);
   100→    emit(-2.5);
   101→    emit(-3.5);
   102→    emit(-4.5);
   103→    emit(-5.5);
   104→
   105→    /* --- Section 6: Near-integer boundary bit patterns (10) --- */
   106→    emit_u(0x3fdffffffffffffeULL);  /* just below 0.5 */
   107→    emit_u(0x3fe0000000000001ULL);  /* just above 0.5 */
   108→    emit_u(0xbfdffffffffffffeULL);  /* just above -0.5 (toward zero) */
   109→    emit_u(0xbfe0000000000001ULL);  /* just below -0.5 (away from zero) */
   110→    emit_u(0x3ff7ffffffffffffULL);  /* just below 1.5 */
   111→    emit_u(0x3ff8000000000001ULL);  /* just above 1.5 */
   112→    emit_u(0xbff7ffffffffffffULL);  /* just above -1.5 (toward zero) */
   113→    emit_u(0xbff8000000000001ULL);  /* just below -1.5 (away from zero) */
   114→    emit_u(0x4003ffffffffffffULL);  /* just below 2.5 */
   115→    emit_u(0x4004000000000001ULL);  /* just above 2.5 */
   116→
   117→    /* --- Section 7: 2^52 integer-precision boundary (8) --- */
   118→    /* At 2^52, adjacent doubles differ by 1.0: floor is identity for integers */
   119→    emit_u(0x4330000000000000ULL);  /* 2^52 exactly = 4503599627370496.0 */
   120→    emit_u(0x432fffffffffffffULL);  /* one ULP below 2^52: last double with fraction */
   121→    emit_u(0x4330000000000001ULL);  /* one ULP above 2^52: all integers here */
   122→    emit_u(0x4340000000000000ULL);  /* 2^53: all representable values are integers */
   123→    emit_u(0x4350000000000000ULL);  /* 2^54 */
   124→    emit_u(0xc330000000000000ULL);  /* -2^52 */
   125→    emit_u(0xc32fffffffffffffULL);  /* one ULP toward zero from -2^52 */
   126→    emit_u(0xc330000000000001ULL);  /* one ULP away from zero from -2^52 */
   127→
   128→    /* --- Section 8: Negative fractional values (10) --- */
   129→    /* floor rounds toward -Inf, so negatives with fractions go more negative */
   130→    emit(-0.1);
   131→    emit(-0.4);
   132→    emit(-0.6);
   133→    emit(-0.9);
   134→    emit(-1.1);
   135→    emit(-1.9);
   136→    emit(-2.1);
   137→    emit(-10.5);
   138→    emit(-100.9);
   139→    emit(-1000.1);
   140→
   141→    /* --- Section 9: Mid-range positive fractional values (8) --- */
   142→    emit(0.1);
   143→    emit(0.4);
   144→    emit(0.6);
   145→    emit(0.9);
   146→    emit(1.1);
   147→    emit(10.7);
   148→    emit(100.5);
   149→    emit(1000.9);
   150→
   151→    /* --- Section 10: Large values and large integer-exact floats (8) --- */
   152→    emit(1.0e15);                   /* large but has fractional ULP spacing */
   153→    emit(-1.0e15);
   154→    emit(1.0e16);                   /* near 2^53: integers only */
   155→    emit(-1.0e16);
   156→    emit(1.0e100);                  /* very large, integer-valued */
   157→    emit(-1.0e100);
   158→    emit(1.0e300);
   159→    emit(-1.0e300);
   160→
   161→    /* --- Section 11: Power-of-2 exponent switching points (19) --- */
   162→    emit(0.25);                     /* 2^-2 */
   163→    emit(0.125);                    /* 2^-3 */
   164→    emit_u(0x3fc0000000000000ULL);  /* 0.125 = 2^-3 exact */
   165→    emit(4.0);
   166→    emit(8.0);
   167→    emit(16.0);
   168→    emit(32.0);
   169→    emit(64.0);
   170→    emit(128.0);
   171→    emit(-4.0);
   172→    emit(-8.0);
   173→    emit(-16.0);
   174→    emit(-32.0);
   175→    emit(-64.0);
   176→    emit(-128.0);
   177→    emit_u(0x4010000000000000ULL);  /* 4.0 exact via bits */
   178→    emit_u(0x4020000000000000ULL);  /* 8.0 exact via bits */
   179→    emit_u(0xc010000000000000ULL);  /* -4.0 exact via bits */
   180→    emit_u(0xc020000000000000ULL);  /* -8.0 exact via bits */
   181→}
