   183→/* ------------------------------------------------------------------ */
   184→
   185→#ifndef EN_PERF
   186→/* 7. Sweep [0, 10] in 100 steps and [-10, 0] in 100 steps */
   187→static void test_sweep(void)
   188→{
   189→    double hi = 10.0;
   190→    int nsteps = 100;
   191→    double step = hi / (double)nsteps;
   192→
   193→    /* [0, 10] */
   194→    for (int i = 0; i <= nsteps; i++)
   195→        emit((double)i * step);
   196→
   197→    /* [-10, 0] */
   198→    for (int i = 0; i <= nsteps; i++)
   199→        emit(-hi + (double)i * step);
   200→}
   201→
   202→/* 8. Sample [0, 10] every ~0.05 (200 points) */
   203→static void test_exhaustive_small(void)
   204→{
   205→    double hi = 10.0;
   206→    int nsteps = 200;
   207→    double step = hi / (double)nsteps;
   208→
   209→    for (int i = 0; i <= nsteps; i++)
   210→        emit((double)i * step);
   211→}
   212→#endif
   213→
   214→/* ------------------------------------------------------------------ */
   215→
   216→int main(void)
   217→{
   218→#ifdef EN_PERF
   219→    startPFM;
   220→    test_representative_100();
   221→    stopPFM;
